#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int numVertices;
    int numEdges;
    int **adjMatrix;
} Graph;

// Function to create a graph
Graph *createGraph(int numVertices, int numEdges) {
    Graph *graph = (Graph *)malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->numEdges = numEdges;
    graph->adjMatrix = (int **)malloc(numVertices * sizeof(int *));
    for (int i = 0; i < numVertices; i++) {
        graph->adjMatrix[i] = (int *)malloc(numVertices * sizeof(int));
        for (int j = 0; j < numVertices; j++) {
            graph->adjMatrix[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph *graph, int u, int v) {
    graph->adjMatrix[u][v] = 1;
    graph->adjMatrix[v][u] = 1;
}

// Function to check if a perfect matching exists
int hasPerfectMatching(Graph *graph) {
    int *matched = (int *)malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        matched[i] = -1;
    }
    for (int i = 0; i < graph->numVertices; i++) {
        for (int j = 0; j < graph->numVertices; j++) {
            if (graph->adjMatrix[i][j] == 1 && matched[i] == -1 && matched[j] == -1) {
                matched[i] = j;
                matched[j] = i;
            }
        }
    }
    for (int i = 0; i < graph->numVertices; i++) {
        if (matched[i] == -1) {
            return 0;
        }
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Graph *graph = createGraph(N, M);
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(graph, u - 1, v - 1);
        }
        if (hasPerfectMatching(graph)) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

