#include <iostream>
#include <vector>
using namespace std;

// Structure to represent a graph
struct Graph {
    int numVertices;
    int numEdges;
    vector<vector<int>> adjList;
};

// Function to create a graph
Graph createGraph(int numVertices, int numEdges) {
    Graph graph;
    graph.numVertices = numVertices;
    graph.numEdges = numEdges;
    graph.adjList.resize(numVertices);
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph &graph, int u, int v) {
    graph.adjList[u].push_back(v);
    graph.adjList[v].push_back(u);
}

// Function to check if a perfect matching exists
bool hasPerfectMatching(Graph &graph) {
    vector<int> matched(graph.numVertices, -1);
    for (int i = 0; i < graph.numVertices; i++) {
        for (int j = 0; j < graph.numVertices; j++) {
            if (find(graph.adjList[i].begin(), graph.adjList[i].end(), j) != graph.adjList[i].end() && matched[i] == -1 && matched[j] == -1) {
                matched[i] = j;
                matched[j] = i;
            }
        }
    }
    for (int i = 0; i < graph.numVertices; i++) {
        if (matched[i] == -1) {
            return false;
        }
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N, M;
        cin >> N >> M;
        Graph graph = createGraph(N, M);
        for (int i = 0; i < M; i++) {
            int u, v;
            cin >> u >> v;
            addEdge(graph, u - 1, v - 1);
        }
