        int numEdges;
        int[][] adjMatrix;

        public Graph(int numVertices, int numEdges) {
            this.numVertices = numVertices;
            this.numEdges = numEdges;
            this.adjMatrix = new int[numVertices][numVertices];
        }
    }

    // Function to add an edge to the graph
    public static void addEdge(Graph graph, int u, int v) {
        graph.adjMatrix[u][v] = 1;
        graph.adjMatrix[v][u] = 1;
    }

    // Function to check if a perfect matching exists
    public static boolean hasPerfectMatching(Graph graph) {
        int[] matched = new int[graph.numVertices];
        for (int i = 0; i < graph.numVertices; i++) {
            matched[i] = -1;
        }
        for (int i = 0; i < graph.numVertices; i++) {
            for (int j = 0; j < graph.numVertices; j++) {
                if (graph.adjMatrix[i][j] == 1 && matched[i] == -1 && matched[j] == -1) {
                    matched[i] = j;
                    matched[j] = i;
                }
            }
        }
        for (int i = 0; i < graph.numVertices; i++) {
            if (matched[i] == -1) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            Graph graph = new Graph(N, M);
            for (int i = 0; i < M; i++) {
                int u = scanner.nextInt() - 1;
                int v = scanner.nextInt() - 1;
                addEdge(graph, u, v);
            }
            if (hasPerfectMatching(graph)) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
