    num_vertices = len(graph)
    matched = [-1] * num_vertices
    for i in range(num_vertices):
        for j in range(num_vertices):
            if j in graph[i] and matched[i] == -1 and matched[j] == -1:
                matched[i] = j
                matched[j] = i
    for i in range(num_vertices):
        if matched[i] == -1:
            return False
    return True

