    const numVertices = graph.length;
    const matched = Array(numVertices).fill(-1);
    for (let i = 0; i < numVertices; i++) {
        for (let j = 0; j < numVertices; j++) {
            if (graph[i].includes(j) && matched[i] === -1 && matched[j] === -1) {
                matched[i] = j;
                matched[j] = i;
            }
        }
    }
    for (let i = 0; i < numVertices; i++) {
